def fib_seq(n: int) -> list:
    """Returns the first n numbers of a Fibonacci-like sequence starting from 1, 3.
    For example, fib_seq(5) should return [1, 3, 4, 7, 11].
    """
    if n <= 0:
        return []
    elif n == 1:
        return [1]
    elif n == 2:
        return [1, 3]
    else:
        result = [1, 3]
        for i in range(2, n):
            next_num = result[i - 1] + result[i - 2]
            result.append(next_num)
        return result
