def pingpong(n: int) -> str:
    """
    Return a string based on the value of `n`:
    - 'Ping'        if n is a multiple of 4 but not 6
    - 'Pong'        if n is a multiple of 6 but not 4
    - 'PingPong'    if n is a multiple of both 4 and 6
    - otherwise the string representation of n
    """
    if n % 4 == 0 and n % 6 == 0:
        return 'PingPong'
    if n % 4 == 0:
        return 'Ping'
    if n % 6 == 0:
        return 'Pong'
    return str(n)

