def ticktock(n: int) -> str:
    """
    Returns 'Tick' for multiples of 2, 'Tock' for multiples of 5, 
    'TickTock' for multiples of both, or the number as a string otherwise.

    Args:
        n: An integer.

    Returns:
        A string based on the divisibility of n.
    """
    if n % 2 == 0 and n % 5 == 0:
        return 'TickTock'
    elif n % 2 == 0:
        return 'Tick'
    elif n % 5 == 0:
        return 'Tock'
    else:
        return str(n)

